 1	import { Label, Tooltip } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	import { AmbientBadge } from '../../components/Ambient/AmbientBadge';
 4	import { Link, useLocation } from 'react-router-dom-v5-compat';
 5	import { meshLinkStyle } from 'components/IstioStatus/IstioStatus';
 6	import { useKialiTranslation } from 'utils/I18nUtils';
 7	
 8	interface ControlPlaneBadgeProps {
 9	  isAmbient?: boolean;
10	}
11	
12	export const ControlPlaneBadge: React.FC<ControlPlaneBadgeProps> = ({ isAmbient = false }) => {
13	  const { t } = useKialiTranslation();
14	  const { pathname } = useLocation();
15	
16	  // Remote clusters do not have istio status because istio is not running there
17	  // so don't display istio status badge for those.
18	  return (
19	    <>
20	      <Tooltip
21	        content={
22	          <>
23	            <span>{t('Istio control plane')}</span>
24	            {!pathname.endsWith('/mesh') && (
25	              <div className={meshLinkStyle}>
26	                <span>{t('More info at')}</span>
27	                <Link to="/mesh">{t('Mesh page')}</Link>
28	              </div>
29	            )}
30	          </>
31	        }
32	      >
33	        <Label style={{ marginLeft: '0.5rem' }} color="green" isCompact data-test="control-plane-badge">
34	          {t('Control plane')}
35	        </Label>
36	      </Tooltip>
37	
38	      {isAmbient && <AmbientBadge tooltip={t('Istio Ambient ztunnel detected in the Control plane')}></AmbientBadge>}
39	    </>
40	  );
41	};

