 3	import { MemoryRouter } from 'react-router-dom-v5-compat';
 4	
 5	describe('ControlPlaneBadge', () => {
 6	  it('does not show istio status for remote clusters', () => {
 7	    const wrapper = shallow(
 8	      <MemoryRouter>
 9	        <ControlPlaneBadge />
10	      </MemoryRouter>
11	    );
12	
13	    expect(wrapper.find('IstioStatus').exists()).toBeFalsy();
